module.exports = {
      fundamentals: {
        id: 'fundamentals',
        name: 'Datadog Fundamentals',
        shortName: 'DD-Fundamentals',
        displayName: 'Datadog Fundamentals',
        description: 'Prepara la certificación oficial gratuita de Datadog: Agent, métricas, dashboards, alertas, logs, APM, Synthetic Monitoring e integraciones.',
        hasPractice: false,
        hasScenarios: false,
        hasConsole: false,
        hasLivePractice: false,
        questions: [
          { id: 1, certification: "fundamentals", category: "Plataforma Datadog", difficulty: "Fácil", question: "¿Qué es Datadog?", options: ["Un sistema operativo para servidores", "Una plataforma de monitorización y observabilidad basada en la nube", "Un lenguaje de programación para análisis de datos", "Una base de datos distribuida"], correctAnswer: 1, explanation: "Datadog es una plataforma SaaS de monitorización y observabilidad que permite visualizar métricas, logs y trazas de toda tu infraestructura y aplicaciones desde un único lugar." },
          { id: 2, certification: "fundamentals", category: "Plataforma Datadog", difficulty: "Fácil", question: "¿Cuáles son los tres pilares de la observabilidad que cubre Datadog?", options: ["CPU, memoria y disco", "Métricas, logs y trazas (traces)", "Frontend, backend y base de datos", "Hosts, contenedores y serverless"], correctAnswer: 1, explanation: "Los tres pilares de la observabilidad son métricas (qué está pasando), logs (por qué está pasando) y trazas (cómo fluye una petición). Datadog integra los tres en una única plataforma." },
          { id: 3, certification: "fundamentals", category: "Plataforma Datadog", difficulty: "Fácil", question: "¿Qué es el Datadog Agent?", options: ["Un agente de ventas de Datadog", "Un software ligero que se instala en los hosts para recopilar métricas, logs y trazas y enviarlos a Datadog", "Una API REST para consultar datos", "Un plugin de navegador para monitorizar webs"], correctAnswer: 1, explanation: "El Datadog Agent es un proceso ligero que se instala en servidores, VMs o contenedores. Recopila métricas del sistema, ejecuta checks de integraciones, recoge logs y trazas APM, y los envía al backend de Datadog." },
          { id: 4, certification: "fundamentals", category: "Plataforma Datadog", difficulty: "Fácil", question: "¿Qué es una integración en Datadog?", options: ["Un contrato de licencia", "Un componente que conecta Datadog con una tecnología externa para recopilar métricas y datos de forma automática", "Un tipo de dashboard", "Un rol de usuario"], correctAnswer: 1, explanation: "Las integraciones conectan Datadog con tecnologías como AWS, Nginx, PostgreSQL o Kubernetes para recopilar métricas, logs y eventos automáticamente sin escribir código personalizado." },
          { id: 5, certification: "fundamentals", category: "Plataforma Datadog", difficulty: "Medio", question: "¿Cuál es la función principal de los tags en Datadog?", options: ["Colorear los dashboards", "Añadir metadatos a los datos para poder filtrar, agrupar y correlacionar métricas, logs y trazas", "Aumentar la velocidad de ingesta de datos", "Cifrar los datos en tránsito"], correctAnswer: 1, explanation: "Los tags son pares clave:valor (ej. env:production, service:web) que añaden contexto a cualquier dato. Permiten filtrar dashboards, definir el alcance de alertas y correlacionar métricas con logs y trazas del mismo servicio." },
          { id: 6, certification: "fundamentals", category: "Datadog Agent", difficulty: "Fácil", question: "¿Cómo se verifica que el Datadog Agent está corriendo correctamente en un host Linux?", options: ["ping datadog.com", "datadog-agent status", "systemctl ping datadog", "curl localhost:8126/status"], correctAnswer: 1, explanation: "El comando 'datadog-agent status' muestra un resumen completo del estado del Agent: checks activos, integraciones, colectores, y posibles errores de configuración." },
          { id: 7, certification: "fundamentals", category: "Datadog Agent", difficulty: "Fácil", question: "¿En qué directorio se encuentra el archivo de configuración principal del Datadog Agent en Linux?", options: ["/etc/datadog/agent.yaml", "/etc/datadog-agent/datadog.yaml", "/opt/datadog/config.yaml", "/var/datadog/config.yaml"], correctAnswer: 1, explanation: "El archivo principal de configuración es /etc/datadog-agent/datadog.yaml. Aquí se define la API key, el hostname, los logs, las integraciones habilitadas y otros parámetros globales del Agent." },
          { id: 8, certification: "fundamentals", category: "Datadog Agent", difficulty: "Medio", question: "¿Qué es un check del Agent en Datadog?", options: ["Una validación de factura", "Un plugin que el Agent ejecuta periódicamente para recopilar métricas de una tecnología específica", "Un test de conectividad de red", "Un tipo de alerta"], correctAnswer: 1, explanation: "Los checks del Agent son plugins (escritos en Python) que el Agent ejecuta cada cierto intervalo para recopilar métricas de una fuente de datos. Existen checks para Nginx, MySQL, Redis, Docker, etc." },
          { id: 9, certification: "fundamentals", category: "Datadog Agent", difficulty: "Medio", question: "¿Cuál es el puerto por defecto que usa el Datadog Agent para recibir métricas DogStatsD?", options: ["8080", "443", "8125", "9090"], correctAnswer: 2, explanation: "DogStatsD escucha en el puerto UDP 8125 por defecto. Las aplicaciones envían métricas personalizadas a este puerto local y el Agent las agrega y reenvía a Datadog." },
          { id: 10, certification: "fundamentals", category: "Datadog Agent", difficulty: "Medio", question: "¿Qué es DogStatsD?", options: ["Un protocolo de base de datos", "Un servidor de estadísticas incluido en el Agent que acepta métricas personalizadas vía UDP desde las aplicaciones", "Una herramienta de diagnóstico de red", "Un tipo de integración cloud"], correctAnswer: 1, explanation: "DogStatsD es una implementación del protocolo StatsD incluida en el Datadog Agent. Las aplicaciones le envían métricas personalizadas (contadores, gauges, histogramas) vía UDP, y el Agent las agrega y envía a Datadog." },
          { id: 11, certification: "fundamentals", category: "Métricas", difficulty: "Fácil", question: "¿Qué es una métrica de tipo gauge en Datadog?", options: ["Un contador que siempre aumenta", "Un valor puntual que representa el estado actual de algo en un momento dado", "Una tasa calculada por segundo", "Un resumen estadístico de múltiples valores"], correctAnswer: 1, explanation: "Un gauge representa un valor puntual que puede subir o bajar: uso de CPU, memoria disponible, número de conexiones activas. Se mide en un instante concreto." },
          { id: 12, certification: "fundamentals", category: "Métricas", difficulty: "Fácil", question: "¿Qué es una métrica de tipo count en Datadog?", options: ["Un valor que se mide en un instante", "El número de eventos que ocurrieron durante un intervalo de tiempo", "Una tasa por segundo", "Un percentil"], correctAnswer: 1, explanation: "Una métrica count acumula el número de eventos durante un intervalo (ej. peticiones HTTP en los últimos 10 segundos). Al enviarse a Datadog se almacena como la suma del intervalo de recopilación." },
          { id: 13, certification: "fundamentals", category: "Métricas", difficulty: "Medio", question: "¿Cuál es la diferencia entre una métrica rate y una count?", options: ["No hay diferencia, son sinónimos", "Rate es el valor por unidad de tiempo (normalizado), count es el total acumulado del intervalo", "Rate se usa solo en APM, count en infraestructura", "Count es más precisa que rate"], correctAnswer: 1, explanation: "Una rate normaliza el count dividiendo por el intervalo de tiempo, dando un valor por segundo. Count muestra el total del intervalo. Rate es más comparable entre distintos intervalos de muestreo." },
          { id: 14, certification: "fundamentals", category: "Métricas", difficulty: "Medio", question: "¿Cuánto tiempo retiene Datadog las métricas por defecto (resolución completa)?", options: ["1 hora", "24 horas", "15 meses", "7 días"], correctAnswer: 2, explanation: "Datadog retiene las métricas con resolución completa (1 punto por segundo) durante 15 meses. Con el tiempo, los datos se agregan a resoluciones menores para el almacenamiento a largo plazo." },
          { id: 15, certification: "fundamentals", category: "Métricas", difficulty: "Medio", question: "¿Qué es una métrica de tipo histogram en Datadog?", options: ["Un tipo de gráfico de barras", "Una métrica que calcula la distribución estadística de valores (percentiles p50, p75, p95, p99, max, avg, count)", "Un tipo de monitor", "Un widget de dashboard"], correctAnswer: 1, explanation: "Un histogram recopila múltiples valores en un intervalo y calcula su distribución estadística: percentiles (p50, p95, p99), media, máximo y count. Ideal para medir latencias de peticiones." },
          { id: 16, certification: "fundamentals", category: "Métricas", difficulty: "Medio", question: "¿Qué función tienen los tags de host en las métricas?", options: ["Aumentan la frecuencia de muestreo", "Permiten filtrar y agregar métricas por dimensiones como entorno, región o equipo", "Cifran los datos de la métrica", "Son obligatorios para enviar métricas"], correctAnswer: 1, explanation: "Los tags de host (ej. env:prod, region:us-east) se adjuntan automáticamente a todas las métricas del host. Permiten filtrar dashboards (mostrar solo prod), crear alertas por entorno y comparar grupos de hosts." },
          { id: 17, certification: "fundamentals", category: "Dashboards", difficulty: "Fácil", question: "¿Cuáles son los dos tipos principales de dashboards en Datadog?", options: ["Público y privado", "Timeboard y Screenboard (ahora unificados como Dashboard)", "Simple y avanzado", "Metrics y Logs"], correctAnswer: 1, explanation: "Históricamente Datadog tenía Timeboards (todos los widgets comparten el mismo rango temporal, ideal para correlación) y Screenboards (layout libre, ideal para TV). Actualmente se unifican bajo 'Dashboard' con opciones de layout." },
          { id: 18, certification: "fundamentals", category: "Dashboards", difficulty: "Fácil", question: "¿Qué son las template variables en un dashboard de Datadog?", options: ["Variables de configuración del Agent", "Filtros dinámicos que permiten cambiar el alcance de todos los widgets del dashboard sin editarlo", "Fórmulas matemáticas para métricas calculadas", "Nombres de hosts hardcodeados"], correctAnswer: 1, explanation: "Las template variables (ej. $env, $host) son filtros globales del dashboard. Al cambiar su valor (de 'prod' a 'staging'), todos los widgets se actualizan automáticamente para mostrar datos del nuevo contexto." },
          { id: 19, certification: "fundamentals", category: "Dashboards", difficulty: "Medio", question: "¿Qué es un widget de tipo Timeseries en Datadog?", options: ["Un widget que muestra el valor actual de una métrica", "Un gráfico de líneas que muestra la evolución de una o varias métricas a lo largo del tiempo", "Una tabla con los valores históricos", "Un mapa geográfico de los hosts"], correctAnswer: 1, explanation: "El widget Timeseries muestra métricas como líneas, áreas o barras a lo largo del tiempo. Es el widget más común para ver tendencias, picos y correlaciones entre métricas." },
          { id: 20, certification: "fundamentals", category: "Dashboards", difficulty: "Medio", question: "¿Qué es el lenguaje de consulta de métricas en Datadog?", options: ["SQL", "PromQL", "La sintaxis de consulta de Datadog basada en 'metric{tags}.function()'", "GraphQL"], correctAnswer: 2, explanation: "Las métricas en Datadog se consultan con una sintaxis propia: 'avg:system.cpu.user{env:prod} by {host}'. Incluye función de agregación, nombre de la métrica, filtro de tags y agrupación por tags." },
          { id: 21, certification: "fundamentals", category: "Dashboards", difficulty: "Medio", question: "¿Qué es un widget de tipo Query Value?", options: ["Un widget que muestra múltiples líneas temporales", "Un widget que muestra un único valor numérico agregado, ideal para KPIs", "Un widget de texto libre", "Un widget de mapa de calor"], correctAnswer: 1, explanation: "El widget Query Value muestra un único valor numérico (ej. la CPU media de los últimos 5 minutos). Se usa para mostrar KPIs, métricas clave o el estado actual de un sistema de forma clara." },
          { id: 22, certification: "fundamentals", category: "Monitors y alertas", difficulty: "Fácil", question: "¿Qué es un Monitor en Datadog?", options: ["Una métrica de salud calculada automáticamente por el Agent para cada host monitorizado", "Una regla que evalúa una condición sobre métricas o datos y genera alertas cuando se cumple", "Un check del Agent que evalúa el estado de un servicio (OK/Warn/Critical) periódicamente", "Un dashboard configurado para mostrar el estado de servicios críticos en tiempo real"], correctAnswer: 1, explanation: "Un Monitor evalúa una condición y genera alertas al cambiar de estado (OK/Warn/Alert/No Data). No confundir con un check del Agent (que recopila datos) ni con un dashboard (que visualiza datos sin generar alertas)." },
          { id: 23, certification: "fundamentals", category: "Monitors y alertas", difficulty: "Fácil", question: "¿Cuáles son los estados posibles de un monitor en Datadog?", options: ["Running, Stopped, Error", "OK, Warn, Alert, No Data", "Active, Inactive, Pending", "Up, Down, Unknown"], correctAnswer: 1, explanation: "Los estados de un monitor son: OK (condición no se cumple), Warn (umbral de advertencia superado), Alert (umbral de alerta superado) y No Data (no se reciben datos)." },
          { id: 24, certification: "fundamentals", category: "Monitors y alertas", difficulty: "Medio", question: "¿Qué es un monitor de tipo Metric en Datadog?", options: ["Un monitor que verifica la disponibilidad de una URL", "Un monitor que evalúa el valor de una métrica frente a un umbral estático o dinámico", "Un monitor que analiza logs", "Un monitor que verifica procesos"], correctAnswer: 1, explanation: "El monitor de tipo Metric evalúa el valor de una métrica (ej. system.cpu.user) frente a un umbral. Puede usar umbrales estáticos o alertas de anomalía/previsión para detectar comportamientos inusuales." },
          { id: 25, certification: "fundamentals", category: "Monitors y alertas", difficulty: "Medio", question: "¿Qué es un monitor de tipo Service Check?", options: ["Un monitor que evalúa métricas de APM", "Un monitor que evalúa el estado devuelto por un check del Agent (OK/Warn/Critical)", "Un monitor de logs", "Un monitor de costes cloud"], correctAnswer: 1, explanation: "Un Service Check monitor evalúa el estado devuelto por checks del Agent como http_check, tcp_check o checks de integración. El estado puede ser OK (0), Warn (1) o Critical (2)." },
          { id: 26, certification: "fundamentals", category: "Monitors y alertas", difficulty: "Medio", question: "¿Qué significa silenciar (mute) un monitor en Datadog?", options: ["Eliminar el monitor permanentemente", "Suprimir temporalmente las notificaciones del monitor sin desactivarlo", "Cambiar el umbral del monitor", "Compartir el monitor con otro equipo"], correctAnswer: 1, explanation: "Silenciar un monitor suprime sus notificaciones durante un tiempo definido (ej. durante una ventana de mantenimiento) sin desactivar la evaluación ni eliminar el monitor." },
          { id: 27, certification: "fundamentals", category: "Monitors y alertas", difficulty: "Medio", question: "¿Qué es el multi-alert en monitores de Datadog?", options: ["Un monitor que envía alertas a múltiples canales", "Un monitor que se evalúa por grupo (ej. por host) y puede alertar/resolver independientemente para cada grupo", "Un monitor con múltiples umbrales", "Un monitor que monitoriza múltiples métricas a la vez"], correctAnswer: 1, explanation: "Con multi-alert y la opción 'group by', el monitor evalúa la condición de forma independiente para cada valor del tag (ej. cada host). Puede estar en Alert para host-A y OK para host-B simultáneamente." },
          { id: 28, certification: "fundamentals", category: "Monitors y alertas", difficulty: "Avanzado", question: "¿Qué es un monitor de tipo Anomaly en Datadog?", options: ["Un monitor que detecta valores fuera de un rango estático", "Un monitor que usa machine learning para detectar comportamientos inusuales basándose en patrones históricos", "Un monitor de errores de aplicación", "Un monitor de logs con regex"], correctAnswer: 1, explanation: "El monitor de Anomaly usa algoritmos de ML (agility, robust, adaptive) para aprender el comportamiento normal de una métrica (estacionalidad, tendencias) y alertar cuando se desvía significativamente del patrón esperado." },
          { id: 29, certification: "fundamentals", category: "Monitors y alertas", difficulty: "Avanzado", question: "¿Qué es un monitor de tipo Forecast en Datadog?", options: ["Un monitor del tiempo meteorológico", "Un monitor que predice si una métrica superará un umbral en el futuro basándose en tendencias históricas", "Un monitor de costes cloud", "Un monitor de SLO"], correctAnswer: 1, explanation: "El monitor Forecast usa ML para predecir el valor futuro de una métrica (ej. el disco llegará al 90% en 48h) y alertar con antelación, antes de que el problema real ocurra." },
          { id: 30, certification: "fundamentals", category: "Monitors y alertas", difficulty: "Medio", question: "¿Qué es un Downtime en Datadog?", options: ["El período en que un host deja de enviar datos y sus monitores entran en estado No Data automáticamente", "Una programación para silenciar monitores durante períodos planificados como mantenimientos", "Una alerta especial de tipo crítico que solo se activa cuando múltiples monitores fallan a la vez", "Un informe automático de disponibilidad generado cuando un monitor permanece en estado Alert"], correctAnswer: 1, explanation: "Un Downtime silencia monitores de forma programada durante mantenimientos planificados. Es distinto del estado No Data (que ocurre cuando el Agent deja de reportar) o de un composite monitor (que combina varios monitores)." },
          { id: 31, certification: "fundamentals", category: "Log Management", difficulty: "Fácil", question: "¿Cuál es el primer paso para empezar a enviar logs a Datadog desde un host?", options: ["Crear un dashboard de logs", "Habilitar la recopilación de logs en el Agent y configurar las fuentes de logs", "Instalar el SDK de logs", "Crear un índice de logs"], correctAnswer: 1, explanation: "Para enviar logs, hay que habilitar 'logs_enabled: true' en datadog.yaml y configurar los archivos o fuentes de log en /etc/datadog-agent/conf.d/. El Agent leerá los archivos y enviará los logs a Datadog." },
          { id: 32, certification: "fundamentals", category: "Log Management", difficulty: "Fácil", question: "¿Qué es un pipeline de logs en Datadog?", options: ["Un tipo de integración de red", "Una secuencia de procesadores que transforman y enriquecen los logs al ser ingeridos", "Un flujo de alertas automáticas", "Un dashboard de logs"], correctAnswer: 1, explanation: "Los pipelines de logs contienen procesadores (Grok Parser, Remapper, URL Parser, etc.) que se aplican secuencialmente para parsear, transformar y enriquecer los logs al entrar en Datadog, extrayendo atributos estructurados del texto." },
          { id: 33, certification: "fundamentals", category: "Log Management", difficulty: "Medio", question: "¿Qué es el Grok Parser en los pipelines de logs de Datadog?", options: ["Un tipo de monitor de logs", "Un procesador que extrae atributos estructurados de logs no estructurados usando patrones Grok", "Un filtro para eliminar logs", "Un tipo de dashboard"], correctAnswer: 1, explanation: "El Grok Parser usa patrones Grok (combinaciones de regex con nombre) para parsear líneas de log no estructuradas y extraer atributos tipados como fecha, IP, nivel de severidad, duración, etc." },
          { id: 34, certification: "fundamentals", category: "Log Management", difficulty: "Medio", question: "¿Qué es un índice de logs en Datadog?", options: ["Un campo searchable dentro de un log", "Una partición de logs que define qué logs se almacenan, por cuánto tiempo y a qué coste", "Un tipo de pipeline", "Un monitor de logs"], correctAnswer: 1, explanation: "Los índices segmentan los logs ingeridos. Cada índice tiene un filtro (qué logs incluye), una retención (3, 7, 15 días, etc.) y un presupuesto de almacenamiento. Permiten gestionar costes indexando solo los logs relevantes." },
          { id: 35, certification: "fundamentals", category: "Log Management", difficulty: "Medio", question: "¿Qué es el Log Archives en Datadog?", options: ["El historial de búsquedas de logs", "La funcionalidad que reenvía logs a almacenamiento propio (S3, GCS, Azure) para retención a largo plazo y bajo coste", "Un tipo de índice de logs", "Un dashboard de logs históricos"], correctAnswer: 1, explanation: "Log Archives reenvía logs a almacenamiento externo (AWS S3, Google Cloud Storage, Azure Blob) de forma comprimida. Permite retención indefinida a bajo coste y rehydratación en Datadog cuando se necesitan para investigación." },
          { id: 36, certification: "fundamentals", category: "Log Management", difficulty: "Medio", question: "¿Qué es Log Rehydration en Datadog?", options: ["Un proceso para parsear logs de nuevo", "La capacidad de importar temporalmente logs almacenados en archives a Datadog para búsqueda e investigación", "Un tipo de pipeline", "Un proceso de compresión de logs"], correctAnswer: 1, explanation: "La rehydratación importa logs desde un archive (S3, GCS, etc.) de vuelta a Datadog de forma temporal para poder buscarlos, correlacionarlos con trazas y analizarlos, sin tenerlos indexados permanentemente." },
          { id: 37, certification: "fundamentals", category: "Log Management", difficulty: "Medio", question: "¿Qué es un log-based metric en Datadog?", options: ["Un tipo de log especial", "Una métrica generada automáticamente a partir del volumen o atributos de los logs ingeridos", "Un monitor de logs", "Un pipeline de logs"], correctAnswer: 1, explanation: "Los log-based metrics generan métricas numéricas a partir de logs: contar eventos (ej. errores HTTP 500 por minuto), medir distribuciones (ej. latencia extraída de logs), con retención de 15 meses a bajo coste." },
          { id: 38, certification: "fundamentals", category: "Log Management", difficulty: "Avanzado", question: "¿Qué es el Log Pattern Analysis en Datadog?", options: ["Un tipo de parseo manual", "Una funcionalidad que agrupa automáticamente logs similares en patrones para detectar tendencias y anomalías", "Un tipo de alerta de logs", "Un informe de retención"], correctAnswer: 1, explanation: "Log Pattern Analysis agrupa automáticamente logs con estructuras similares usando ML, permitiendo ver rápidamente qué tipos de eventos son más frecuentes y detectar patrones nuevos o inusuales sin buscar manualmente." },
          { id: 39, certification: "fundamentals", category: "APM", difficulty: "Fácil", question: "¿Qué es APM en Datadog?", options: ["Application Performance Monitoring: rastrea el rendimiento de aplicaciones mediante trazas distribuidas", "Automatic Process Management: gestiona procesos del sistema", "Advanced Plugin Manager: gestiona integraciones", "API Performance Metrics: métricas de APIs externas"], correctAnswer: 0, explanation: "APM (Application Performance Monitoring) en Datadog rastrea peticiones a través de servicios distribuidos mediante trazas (traces) y spans, permitiendo ver latencias, errores y el flujo completo de una petición." },
          { id: 40, certification: "fundamentals", category: "APM", difficulty: "Fácil", question: "¿Qué es una traza (trace) en Datadog APM?", options: ["Un log de error de aplicación", "El recorrido completo de una petición a través de todos los servicios que atraviesa, compuesto por spans", "Un tipo de métrica de latencia", "Un tipo de alerta de APM"], correctAnswer: 1, explanation: "Una traza representa el ciclo de vida completo de una petición: desde que entra en el primer servicio hasta que devuelve la respuesta, pasando por todos los servicios intermedios. Está compuesta por uno o más spans." },
          { id: 41, certification: "fundamentals", category: "APM", difficulty: "Fácil", question: "¿Qué es un span en Datadog APM?", options: ["Un tipo de dashboard de APM", "La unidad de trabajo dentro de una traza que representa una operación individual en un servicio", "Un log estructurado de APM", "Un umbral de latencia"], correctAnswer: 1, explanation: "Un span representa una única operación dentro de una traza (ej. una consulta SQL, una llamada HTTP, una función). Tiene un nombre, duración, estado (error o no) y metadatos (tags, resource name)." },
          { id: 42, certification: "fundamentals", category: "APM", difficulty: "Medio", question: "¿Qué es el Service Map en Datadog?", options: ["Un mapa geográfico de los servidores", "Una visualización automática de las dependencias entre servicios basada en las trazas de APM", "Un tipo de dashboard de infraestructura", "Una lista de servicios configurados manualmente"], correctAnswer: 1, explanation: "El Service Map genera automáticamente un grafo de las dependencias entre servicios a partir de las trazas APM, mostrando qué servicios se llaman entre sí y su estado de salud (latencia, tasa de error)." },
          { id: 43, certification: "fundamentals", category: "APM", difficulty: "Medio", question: "¿Qué es un flame graph en Datadog APM?", options: ["Un tipo de gráfico de métricas", "Una visualización jerárquica de los spans de una traza que muestra dónde se invierte el tiempo en una petición", "Un tipo de alerta de APM", "Un widget de dashboard"], correctAnswer: 1, explanation: "El flame graph (gráfico de llamas) muestra los spans de una traza como bloques apilados, donde el ancho representa el tiempo consumido. Permite identificar rápidamente qué operación es el cuello de botella de una petición lenta." },
          { id: 44, certification: "fundamentals", category: "APM", difficulty: "Medio", question: "¿Qué es el muestreo (sampling) de trazas en Datadog?", options: ["Un tipo de métrica de APM", "La práctica de enviar solo un porcentaje de las trazas para controlar el coste y el volumen de datos", "Un tipo de alerta de APM", "La configuración del Agent"], correctAnswer: 1, explanation: "El sampling controla qué porcentaje de trazas se envían a Datadog (por defecto ~1 traza/s por servicio con head-based sampling). Permite analizar el rendimiento sin almacenar el 100% de las peticiones." },
          { id: 45, certification: "fundamentals", category: "APM", difficulty: "Avanzado", question: "¿Qué es el Continuous Profiler de Datadog?", options: ["Un tipo de test de carga", "Una funcionalidad que recopila perfiles de código en producción (CPU, memoria, latencia) con bajo overhead para identificar ineficiencias", "Un monitor de APM avanzado", "Un tipo de integración de CI/CD"], correctAnswer: 1, explanation: "El Continuous Profiler captura perfiles de código en producción (qué funciones consumen más CPU o memoria) con un overhead muy bajo, permitiendo identificar hot paths y optimizar el rendimiento sin necesidad de test de carga." },
          { id: 46, certification: "fundamentals", category: "APM", difficulty: "Medio", question: "¿Qué es un SLO (Service Level Objective) en Datadog?", options: ["Un tipo de monitor de logs", "Un objetivo cuantificable de rendimiento de un servicio (ej. 99.9% de disponibilidad) rastreado durante un período de tiempo", "Un tipo de integración", "Un dashboard de costes"], correctAnswer: 1, explanation: "Un SLO define el nivel de rendimiento esperado de un servicio (disponibilidad, latencia, tasa de error) y un período de cumplimiento. Datadog rastrea si el servicio cumple el objetivo y calcula el error budget restante." },
          { id: 47, certification: "fundamentals", category: "APM", difficulty: "Medio", question: "¿Qué es el Error Tracking en Datadog APM?", options: ["Un tipo de log de errores", "Una funcionalidad que agrupa automáticamente errores similares de APM y logs en issues para facilitar su investigación", "Un tipo de monitor", "Un widget de dashboard"], correctAnswer: 1, explanation: "Error Tracking agrupa automáticamente errores similares (mismo stack trace) en issues únicos, muestra su frecuencia, los servicios afectados y permite asignarlos a equipos para su resolución, reduciendo el ruido de alertas repetitivas." },
          { id: 48, certification: "fundamentals", category: "Infraestructura", difficulty: "Fácil", question: "¿Qué muestra la Infrastructure List en Datadog?", options: ["Una lista de todos los dashboards creados", "Un inventario de todos los hosts monitorizados con sus métricas clave y tags", "Una lista de todas las integraciones activas", "Un listado de todos los monitores"], correctAnswer: 1, explanation: "La Infrastructure List muestra todos los hosts que reportan al Agent con sus métricas principales (CPU, memoria, disco), tags asignados, integraciones activas y el estado de las apps instaladas." },
          { id: 49, certification: "fundamentals", category: "Infraestructura", difficulty: "Fácil", question: "¿Qué es el Host Map en Datadog?", options: ["Un mapa geográfico de centros de datos", "Una visualización de todos los hosts como hexágonos coloreados por el valor de una métrica para identificar patrones visualmente", "Un diagrama de red", "Un mapa de dependencias de servicios"], correctAnswer: 1, explanation: "El Host Map muestra todos los hosts como hexágonos. El color de cada hexágono representa el valor de una métrica elegida (ej. CPU usage). Permite identificar de un vistazo qué hosts tienen problemas y agruparlos por tags." },
          { id: 50, certification: "fundamentals", category: "Infraestructura", difficulty: "Medio", question: "¿Qué es el Live Container Monitoring en Datadog?", options: ["Un tipo de integración de Docker", "Una vista en tiempo real de todos los contenedores en ejecución con sus métricas de rendimiento, logs y trazas", "Un monitor específico para contenedores", "Un dashboard de Kubernetes"], correctAnswer: 1, explanation: "Live Container Monitoring ofrece una vista en tiempo real de todos los contenedores (Docker, Kubernetes) con métricas de CPU, memoria, red, I/O por contenedor, junto con sus logs y trazas APM, todo correlacionado." },
          { id: 51, certification: "fundamentals", category: "Infraestructura", difficulty: "Medio", question: "¿Qué es el Process Monitoring en Datadog?", options: ["Un monitor de procesos de negocio", "La funcionalidad que recopila información de todos los procesos en ejecución en los hosts (CPU, memoria, PID, comando)", "Un tipo de integración de sistema operativo", "Un widget de dashboard"], correctAnswer: 1, explanation: "Process Monitoring recopila información de cada proceso en ejecución: PID, usuario, CPU, memoria, comando. Permite crear monitores de procesos (alertar si un proceso deja de correr) y ver tendencias históricas." },
          { id: 52, certification: "fundamentals", category: "Infraestructura", difficulty: "Medio", question: "¿Qué es Network Performance Monitoring (NPM) en Datadog?", options: ["Un tipo de integración de red", "Una funcionalidad que monitoriza el tráfico de red entre procesos y hosts, mostrando latencia y volumen por flujo", "Un monitor de ancho de banda", "Un tipo de log de red"], correctAnswer: 1, explanation: "NPM monitoriza las comunicaciones de red a nivel de flujo (source→destination) entre procesos, hosts, pods o servicios, mostrando bytes enviados, retransmisiones TCP y latencia de red para diagnosticar problemas de conectividad." },
          { id: 53, certification: "fundamentals", category: "Integraciones cloud", difficulty: "Fácil", question: "¿Cómo se integra Datadog con AWS?", options: ["Instalando el Agent en cada instancia EC2", "Mediante una integración basada en roles IAM que permite a Datadog leer métricas de CloudWatch y otros servicios AWS", "Solo mediante exportación manual de CSV desde la consola AWS", "Usando únicamente la API de Datadog"], correctAnswer: 1, explanation: "La integración AWS usa un rol IAM con permisos de lectura para recopilar métricas de CloudWatch, inventario de recursos (EC2, RDS, S3, Lambda...), eventos de CloudTrail y logs automáticamente." },
          { id: 54, certification: "fundamentals", category: "Integraciones cloud", difficulty: "Fácil", question: "¿Qué ventaja tiene instalar el Datadog Agent en instancias EC2 además de usar la integración AWS?", options: ["Reduce el coste de la integración AWS", "Proporciona métricas del sistema operativo (CPU por proceso, memoria, disco, red) y checks de aplicaciones que CloudWatch no ofrece", "Es obligatorio para usar la integración AWS", "Permite monitorizar S3 y Lambda"], correctAnswer: 1, explanation: "La integración AWS recoge métricas de CloudWatch (disponibles cada 5min). El Agent instalado en EC2 añade métricas del SO con mayor granularidad (cada 15s), checks de aplicaciones (Nginx, MySQL) y recopilación de logs." },
          { id: 55, certification: "fundamentals", category: "Integraciones cloud", difficulty: "Medio", question: "¿Qué es el etiquetado unificado de servicios (Unified Service Tagging) en Datadog?", options: ["Un sistema de facturación", "La práctica de aplicar los tags env, service y version a todos los datos (métricas, logs, trazas) para correlación completa", "Un tipo de integración", "Una política de seguridad"], correctAnswer: 1, explanation: "Unified Service Tagging estandariza tres tags clave: env (entorno), service (nombre del servicio) y version (versión desplegada). Al aplicarlos a métricas, logs y trazas, se puede correlacionar cualquier dato de un servicio en cualquier contexto." },
          { id: 56, certification: "fundamentals", category: "Integraciones cloud", difficulty: "Medio", question: "¿Qué es el AWS Lambda Monitoring en Datadog?", options: ["Un monitor que verifica que Lambda está activo", "La monitorización de funciones Lambda con métricas, trazas y logs sin necesidad de instalar el Agent", "Un tipo de integración de costes cloud", "Un dashboard predefinido de Lambda"], correctAnswer: 1, explanation: "Datadog monitoriza funciones Lambda mediante la extensión Lambda o capas (layers), recopilando métricas de invocación, duración, errores y cold starts, trazas APM y logs, todo correlacionado sin instalar el Agent completo." },
          { id: 57, certification: "fundamentals", category: "Synthetic Monitoring", difficulty: "Fácil", question: "¿Qué es el Synthetic Monitoring en Datadog?", options: ["Monitorización de datos sintéticos de entrenamiento de ML", "Pruebas proactivas que simulan usuarios reales para verificar la disponibilidad y el rendimiento de APIs y aplicaciones web", "Un tipo de test de carga", "Un monitor de métricas de frontend"], correctAnswer: 1, explanation: "Synthetic Monitoring ejecuta pruebas automatizadas desde múltiples ubicaciones globales para verificar que APIs y aplicaciones web funcionan correctamente, detectando problemas antes de que afecten a usuarios reales." },
          { id: 58, certification: "fundamentals", category: "Synthetic Monitoring", difficulty: "Fácil", question: "¿Cuáles son los dos tipos de tests en Synthetic Monitoring?", options: ["Test unitario y test de integración", "API test y Browser test", "Test de carga y test de estrés", "Test de seguridad y test de rendimiento"], correctAnswer: 1, explanation: "Los API tests verifican endpoints HTTP, DNS, TCP, SSL y gRPC desde múltiples ubicaciones. Los Browser tests graban y reproducen interacciones de usuario en un navegador real para verificar flujos completos de la UI." },
          { id: 59, certification: "fundamentals", category: "Synthetic Monitoring", difficulty: "Medio", question: "¿Qué son los Synthetic Private Locations?", options: ["Tests que se ejecutan solo en redes privadas", "Agentes de Synthetic desplegados en la infraestructura propia para monitorizar aplicaciones internas no accesibles desde Internet", "Un tipo de VPN para Datadog", "Tests programados fuera del horario laboral"], correctAnswer: 1, explanation: "Los Private Locations son contenedores Docker que se despliegan en la infraestructura propia y actúan como agentes de Synthetic, permitiendo monitorizar aplicaciones internas (staging, intranet) que no son accesibles desde los workers públicos de Datadog." },
          { id: 60, certification: "fundamentals", category: "Synthetic Monitoring", difficulty: "Medio", question: "¿Qué mide el tiempo de respuesta (response time) en un API test de Synthetic?", options: ["El tiempo que tarda el DNS en resolverse", "El tiempo total desde que se envía la petición hasta que se recibe la respuesta completa", "El tiempo de procesamiento del servidor únicamente", "El tiempo de red sin incluir el procesamiento"], correctAnswer: 1, explanation: "El response time en un API test incluye el tiempo total: resolución DNS, establecimiento de conexión TCP/TLS, envío de la petición, procesamiento del servidor y recepción de la respuesta. Permite detectar degradaciones end-to-end." },
          { id: 61, certification: "fundamentals", category: "Synthetic Monitoring", difficulty: "Avanzado", question: "¿Qué son los Synthetic multistep API tests?", options: ["Tests que ejecutan múltiples navegadores en paralelo", "Tests que encadenan múltiples peticiones HTTP en secuencia, reutilizando variables entre pasos para probar flujos complejos", "Tests con múltiples umbrales de alerta", "Tests que se ejecutan en múltiples ubicaciones simultáneamente"], correctAnswer: 1, explanation: "Los Multistep API tests permiten encadenar múltiples peticiones HTTP donde la respuesta de un paso puede usarse en el siguiente (ej. login → obtener token → usar token en petición autenticada), verificando flujos transaccionales completos." },
          { id: 62, certification: "fundamentals", category: "Seguridad y administración", difficulty: "Fácil", question: "¿Qué es una API Key en Datadog?", options: ["Una clave personal que junto con la API Key autentica operaciones de gestión en la API REST de Datadog", "Una clave que autentica el envío de datos al backend de Datadog (usada por el Agent y las integraciones)", "Una clave de cifrado que protege la comunicación entre el Agent y el backend de Datadog", "Una clave que identifica de forma única a cada usuario de Datadog para el acceso al dashboard"], correctAnswer: 1, explanation: "La API Key autentica el envío de datos (métricas, logs, trazas) desde el Agent y las integraciones. No confundir con la Application Key (que autentica llamadas a la API de gestión) ni con las credenciales de usuario para el dashboard." },
          { id: 63, certification: "fundamentals", category: "Seguridad y administración", difficulty: "Fácil", question: "¿Para qué se usa una Application Key (App Key) en Datadog?", options: ["Para autenticar el envío de datos (métricas, logs, trazas) desde el Agent al backend de Datadog", "Para autenticar llamadas a la API de Datadog y realizar operaciones de lectura/escritura en la plataforma", "Para firmar digitalmente los datos del Agent y garantizar su integridad durante el envío", "Para vincular la cuenta de Datadog con proveedores cloud como AWS o GCP en integraciones basadas en API"], correctAnswer: 1, explanation: "La Application Key autentica llamadas a la API REST de Datadog para gestionar monitores, dashboards y configuración. No envía datos de monitorización (eso es la API Key) ni vincula integraciones cloud (que usan roles IAM o credenciales del proveedor)." },
          { id: 64, certification: "fundamentals", category: "Seguridad y administración", difficulty: "Medio", question: "¿Qué es el RBAC (Role-Based Access Control) en Datadog?", options: ["Un tipo de integración de seguridad", "Un sistema que controla qué recursos y funcionalidades puede acceder cada usuario según su rol asignado", "Un monitor de seguridad", "Un tipo de log de auditoría"], correctAnswer: 1, explanation: "RBAC en Datadog asigna permisos a usuarios mediante roles (Admin, Standard, Read-Only) o roles personalizados. Controla acceso a dashboards, monitores, logs, APM y configuración, garantizando el principio de mínimo privilegio." },
          { id: 65, certification: "fundamentals", category: "Seguridad y administración", difficulty: "Medio", question: "¿Qué es una organización (Org) en Datadog?", options: ["Un entorno separado dentro de la misma cuenta para aislar datos de distintos equipos o proyectos", "Una cuenta de Datadog aislada con sus propios datos, usuarios, integraciones y configuración", "Un workspace que agrupa dashboards, monitores e integraciones relacionados por dominio o equipo", "Un grupo de hosts y servicios organizados mediante tags que comparten políticas de monitorización"], correctAnswer: 1, explanation: "Una Org es una cuenta completamente aislada con su propio backend de datos y usuarios. No es solo una separación lógica dentro de una cuenta (como grupos o tags), sino una instancia independiente de Datadog." },
          { id: 66, certification: "fundamentals", category: "Seguridad y administración", difficulty: "Medio", question: "¿Qué es el Audit Trail en Datadog?", options: ["Un tipo de log de aplicación", "Un registro inmutable de todas las acciones realizadas por usuarios y sistemas en la plataforma Datadog", "Un monitor de seguridad automático", "Un tipo de integración de SIEM"], correctAnswer: 1, explanation: "Audit Trail registra todas las acciones en la plataforma: quién creó un dashboard, modificó un monitor, accedió a datos sensibles, etc. Los registros son inmutables y exportables, facilitando el cumplimiento normativo y la investigación de incidentes." },
          { id: 67, certification: "fundamentals", category: "Seguridad y administración", difficulty: "Avanzado", question: "¿Qué es Sensitive Data Scanner en Datadog?", options: ["Un antivirus para los servidores monitorizados", "Una funcionalidad que detecta y enmascara automáticamente datos sensibles (PII, contraseñas, tokens) en los logs ingeridos", "Un tipo de monitor de seguridad", "Un plugin del Agent"], correctAnswer: 1, explanation: "Sensitive Data Scanner analiza los logs en tiempo real al ser ingeridos y detecta patrones de datos sensibles (tarjetas de crédito, SSN, emails, API keys) usando reglas preconstruidas o personalizadas, enmascarándolos antes de indexarlos." },
          { id: 68, certification: "fundamentals", category: "Integraciones", difficulty: "Fácil", question: "¿Cuántas integraciones oficiales ofrece Datadog aproximadamente?", options: ["Menos de 50", "Alrededor de 100", "Más de 700", "Exactamente 300"], correctAnswer: 2, explanation: "Datadog ofrece más de 700 integraciones oficiales con tecnologías de infraestructura, aplicaciones, clouds, bases de datos, herramientas de CI/CD, notificaciones y más. También permite crear integraciones personalizadas." },
          { id: 69, certification: "fundamentals", category: "Integraciones", difficulty: "Medio", question: "¿Qué es una integración basada en Agent en Datadog?", options: ["Una integración que no requiere el Agent", "Una integración configurada en el Agent que ejecuta checks periódicos para recopilar métricas de una tecnología local", "Un tipo de integración cloud", "Una integración de red"], correctAnswer: 1, explanation: "Las integraciones basadas en Agent (ej. Nginx, MySQL, Redis) se configuran en /etc/datadog-agent/conf.d/ y el Agent ejecuta checks periódicos contra el servicio local para recopilar métricas, eventos y logs específicos." },
          { id: 70, certification: "fundamentals", category: "Integraciones", difficulty: "Medio", question: "¿Qué es una integración crawler o basada en API en Datadog?", options: ["Una integración que instala el Agent remotamente", "Una integración que Datadog consulta directamente mediante una API externa sin necesidad del Agent en los hosts", "Un tipo de integración de log", "Una integración de seguridad"], correctAnswer: 1, explanation: "Las integraciones crawler (ej. AWS, GCP, Azure, Salesforce) funcionan sin el Agent: Datadog llama periódicamente a APIs externas (CloudWatch, Azure Monitor, GCP Monitoring) con credenciales para recopilar métricas e inventario." },
          { id: 71, certification: "fundamentals", category: "Kubernetes", difficulty: "Fácil", question: "¿Cómo se despliega Datadog en un clúster Kubernetes?", options: ["Instalando el Agent como aplicación systemd en cada nodo", "Mediante un DaemonSet que despliega el Agent en cada nodo y un Cluster Agent para métricas a nivel de clúster", "Usando únicamente la integración cloud de Kubernetes", "Instalando el Agent en el nodo master solamente"], correctAnswer: 1, explanation: "En Kubernetes se despliega el Node Agent como DaemonSet (un pod por nodo para métricas del nodo y contenedores) y el Cluster Agent como Deployment (métricas a nivel de clúster, Events, HPA, Service Checks)." },
          { id: 72, certification: "fundamentals", category: "Kubernetes", difficulty: "Medio", question: "¿Qué es el Datadog Cluster Agent?", options: ["El Agent que monitoriza el nodo master", "Un componente centralizado que recoge métricas del plano de control de Kubernetes y sirve como proxy de metadatos para los Node Agents", "Un tipo de integración de Kubernetes", "Un dashboard de Kubernetes"], correctAnswer: 1, explanation: "El Cluster Agent recoge métricas del API server de Kubernetes (Events, estado de Deployments, HPA), aplica Autodiscovery centralizado y sirve como proxy de metadatos del clúster a los Node Agents, reduciendo la carga en el API server." },
          { id: 73, certification: "fundamentals", category: "Kubernetes", difficulty: "Medio", question: "¿Qué es Autodiscovery en Datadog?", options: ["Una funcionalidad de auto-escalado", "La capacidad del Agent de detectar automáticamente contenedores en ejecución y aplicar configuraciones de checks según sus labels/annotations", "Un tipo de integración cloud", "Una funcionalidad de dashboards"], correctAnswer: 1, explanation: "Autodiscovery permite que el Agent detecte contenedores nuevos y aplique automáticamente la configuración de check correcta según las annotations/labels del pod (ej. al detectar un pod Nginx, aplica el check de Nginx automáticamente)." },
          { id: 74, certification: "fundamentals", category: "Kubernetes", difficulty: "Avanzado", question: "¿Qué son las Datadog Admission Controller webhooks en Kubernetes?", options: ["Un tipo de monitor de Kubernetes", "Webhooks que inyectan automáticamente variables de entorno APM y configuración del Agent en los pods al ser creados", "Un tipo de integración", "Un dashboard de Kubernetes avanzado"], correctAnswer: 1, explanation: "El Admission Controller de Datadog intercepta la creación de pods e inyecta automáticamente las variables de entorno necesarias para APM (DD_AGENT_HOST, DD_ENV, DD_SERVICE, DD_VERSION) sin modificar los manifiestos de los pods." },
          { id: 75, certification: "fundamentals", category: "Métricas avanzadas", difficulty: "Medio", question: "¿Qué es una métrica de tipo distribution en Datadog?", options: ["Una métrica que se distribuye entre múltiples hosts", "Un tipo de métrica que almacena la distribución completa de valores para calcular percentiles precisos globalmente", "Una métrica de red", "Un tipo de gauge distribuido"], correctAnswer: 1, explanation: "Las métricas distribution (DDSketch) almacenan la distribución estadística completa de todos los valores enviados desde todos los hosts, permitiendo calcular percentiles globalmente precisos (p50, p95, p99) sin muestreo." },
          { id: 76, certification: "fundamentals", category: "Métricas avanzadas", difficulty: "Medio", question: "¿Qué es una función de rollup en las consultas de métricas de Datadog?", options: ["Un tipo de alarma", "Una función que controla cómo se agregan los puntos de datos en el tiempo al visualizar en un rango de tiempo amplio", "Un tipo de métrica", "Una función de exportación de datos"], correctAnswer: 1, explanation: "La función rollup() especifica el intervalo de tiempo para agregar los puntos de datos y el método de agregación (avg, sum, max, min). Datadog aplica rollup automático al ampliar el rango de tiempo del gráfico." },
          { id: 77, certification: "fundamentals", category: "Métricas avanzadas", difficulty: "Avanzado", question: "¿Qué son las métricas custom (custom metrics) en Datadog?", options: ["Métricas con nombres que empiezan por 'custom.'", "Métricas que no son generadas automáticamente por las integraciones estándar, enviadas manualmente por las aplicaciones", "Métricas de alta resolución", "Métricas de terceros"], correctAnswer: 1, explanation: "Las custom metrics son métricas enviadas por las aplicaciones (via DogStatsD, API o SDK) que no forman parte de las integraciones estándar. Se cuentan para la facturación y cada combinación única de nombre+tags cuenta como una custom metric." },
          { id: 78, certification: "fundamentals", category: "Dashboards avanzados", difficulty: "Medio", question: "¿Qué es un widget de Heatmap en Datadog?", options: ["Un mapa de calor geográfico", "Un widget que muestra la distribución de valores de una métrica a lo largo del tiempo usando intensidad de color", "Un tipo de monitor visual", "Un widget de temperatura de servidores"], correctAnswer: 1, explanation: "El widget Heatmap muestra la distribución de valores de una métrica (típicamente histogramas o distribuciones) a lo largo del tiempo. El color indica la densidad de valores en cada rango, ideal para visualizar latencias y distribuciones." },
          { id: 79, certification: "fundamentals", category: "Dashboards avanzados", difficulty: "Medio", question: "¿Qué es un widget de Toplist en Datadog?", options: ["Un widget que muestra los errores más recientes", "Un widget que muestra los N elementos con mayor o menor valor de una métrica, ordenados por valor", "Un widget de logs en tiempo real", "Un widget de alertas activas"], correctAnswer: 1, explanation: "El widget Toplist muestra los N elementos (hosts, servicios, endpoints) con el mayor o menor valor de una métrica, ordenados de mayor a menor. Ideal para responder '¿qué hosts consumen más CPU?' o '¿qué endpoints tienen mayor latencia?'." },
          { id: 80, certification: "fundamentals", category: "Dashboards avanzados", difficulty: "Avanzado", question: "¿Qué son los Notebook en Datadog?", options: ["Un tipo de dashboard", "Documentos colaborativos que combinan gráficos de métricas, logs y texto para análisis post-mortem e investigación de incidentes", "Un tipo de integración", "Un tipo de monitor"], correctAnswer: 1, explanation: "Los Notebooks de Datadog son documentos colaborativos (similar a Jupyter) que combinan visualizaciones de métricas, consultas de logs, texto en markdown y trazas APM. Se usan para post-mortems, runbooks e investigación de incidentes." },
          { id: 81, certification: "fundamentals", category: "Alertas avanzadas", difficulty: "Medio", question: "¿Qué es un monitor compuesto (composite monitor) en Datadog?", options: ["Un monitor que alerta sobre múltiples métricas a la vez", "Un monitor que combina el estado de dos o más monitores existentes con operadores lógicos (AND, OR) para alertar en condiciones complejas", "Un monitor con múltiples umbrales", "Un monitor de APM compuesto"], correctAnswer: 1, explanation: "Un Composite Monitor combina el estado de múltiples monitores con AND/OR: ej. alertar solo cuando CPU > 90% AND memoria > 85% al mismo tiempo. Reduce false positives al requerir múltiples condiciones simultáneas." },
          { id: 82, certification: "fundamentals", category: "Alertas avanzadas", difficulty: "Medio", question: "¿Qué son los Webhooks como canal de notificación en Datadog?", options: ["Un tipo de monitor", "Integraciones que permiten enviar notificaciones de monitores a cualquier servicio externo mediante una llamada HTTP POST", "Un tipo de dashboard", "Un tipo de métrica"], correctAnswer: 1, explanation: "Los Webhooks envían una petición HTTP POST con el payload de la alerta (JSON con estado, título, query, tags) a cualquier URL cuando un monitor cambia de estado, permitiendo integrar con cualquier sistema externo." },
          { id: 83, certification: "fundamentals", category: "Alertas avanzadas", difficulty: "Avanzado", question: "¿Qué es Watchdog en Datadog?", options: ["Un monitor de seguridad para detectar intrusos", "Un motor de IA que detecta automáticamente anomalías en métricas de infraestructura y APM sin necesidad de configurar umbrales", "Un tipo de integración", "Una funcionalidad de logs"], correctAnswer: 1, explanation: "Watchdog usa algoritmos de ML para detectar automáticamente anomalías en métricas de aplicaciones e infraestructura (picos de latencia, incrementos de tasa de error, cambios en throughput) y las presenta en un feed sin necesidad de configurar monitores." },
          { id: 84, certification: "fundamentals", category: "Log Management avanzado", difficulty: "Medio", question: "¿Qué son los exclusion filters en los índices de logs?", options: ["Filtros que eliminan logs duplicados", "Reglas que excluyen un porcentaje o todos los logs que cumplen una condición de un índice para controlar costes", "Filtros de búsqueda en el Log Explorer", "Reglas de transformación de logs"], correctAnswer: 1, explanation: "Los Exclusion Filters en los índices permiten excluir logs que cumplen una condición (ej. logs de salud de Kubernetes) de forma total o parcial (muestreo), reduciendo el volumen indexado y el coste sin perder logs críticos." },
          { id: 85, certification: "fundamentals", category: "Log Management avanzado", difficulty: "Avanzado", question: "¿Qué es Log Forwarding en Datadog?", options: ["El proceso de enviar logs desde el Agent", "La funcionalidad que reenvía logs ingeridos a destinos externos como S3, Splunk, Elasticsearch o SIEM", "Un tipo de pipeline de logs", "Un tipo de índice de logs"], correctAnswer: 1, explanation: "Log Forwarding (anteriormente Log Destinations) permite reenviar todos los logs o un subconjunto filtrado a destinos externos como S3, Azure Blob, Google Cloud Storage, Splunk o HTTP endpoints, para cumplimiento o análisis adicional." },
          { id: 86, certification: "fundamentals", category: "Integraciones avanzadas", difficulty: "Medio", question: "¿Qué es la integración de Datadog con PagerDuty?", options: ["Un tipo de monitor de PagerDuty", "Una integración que envía alertas de monitores de Datadog a PagerDuty para gestión de incidentes y on-call", "Un tipo de dashboard de incidentes", "Una integración de facturación"], correctAnswer: 1, explanation: "La integración PagerDuty recibe notificaciones de monitores de Datadog y crea/resuelve incidentes en PagerDuty automáticamente, incluyendo el estado del monitor, la query y los tags, para gestión de on-call y escalación." },
          { id: 87, certification: "fundamentals", category: "Integraciones avanzadas", difficulty: "Medio", question: "¿Qué información se puede enviar desde Datadog a Slack?", options: ["Solo el nombre del monitor", "Notificaciones de alertas con estado, gráficas, links y contexto cuando un monitor cambia de estado", "Solo métricas en formato CSV", "Solo logs de error"], correctAnswer: 1, explanation: "La integración Slack de Datadog envía mensajes de notificación a canales de Slack cuando un monitor alerta o se resuelve, incluyendo el estado, el título, la condición, las tags afectadas y un link directo al monitor en Datadog." },
          { id: 88, certification: "fundamentals", category: "Integraciones avanzadas", difficulty: "Avanzado", question: "¿Qué es el Datadog Marketplace?", options: ["La biblioteca de las más de 700 integraciones oficiales de Datadog incluidas en la suscripción estándar", "Una plataforma donde partners y clientes pueden publicar y comprar integraciones, apps y servicios adicionales para Datadog", "El catálogo de checks de Agent open source de la comunidad que cualquiera puede instalar gratuitamente", "El portal de licencias de Datadog donde se gestionan las suscripciones y los add-ons de producto"], correctAnswer: 1, explanation: "El Marketplace es distinto de las integraciones oficiales estándar (que son gratuitas y mantenidas por Datadog) y de la comunidad open source (integrations-extras). En el Marketplace los partners ofrecen contenido de pago o con soporte especializado." },
          { id: 89, certification: "fundamentals", category: "Real User Monitoring", difficulty: "Fácil", question: "¿Qué es RUM (Real User Monitoring) en Datadog?", options: ["Monitorización de redes de entrega de contenido", "La monitorización de la experiencia real de los usuarios en aplicaciones web y móviles: rendimiento, errores y comportamiento", "Un tipo de Synthetic test", "Un monitor de frontend"], correctAnswer: 1, explanation: "RUM recopila datos de rendimiento y comportamiento de usuarios reales: page load times, Core Web Vitals, errores JavaScript, interacciones del usuario y sesiones completas, permitiendo detectar problemas de UX que Synthetic no puede." },
          { id: 90, certification: "fundamentals", category: "Real User Monitoring", difficulty: "Medio", question: "¿Qué son las Core Web Vitals que monitoriza Datadog RUM?", options: ["Métricas de CPU del servidor web", "Métricas de Google para medir la experiencia del usuario: LCP (carga), FID/INP (interactividad) y CLS (estabilidad visual)", "Tipos de errores de JavaScript", "Métricas de red del servidor"], correctAnswer: 1, explanation: "Las Core Web Vitals son métricas de Google que miden la experiencia del usuario: LCP (Largest Contentful Paint, carga), FID/INP (First Input Delay/Interaction to Next Paint, interactividad) y CLS (Cumulative Layout Shift, estabilidad visual)." },
          { id: 91, certification: "fundamentals", category: "Real User Monitoring", difficulty: "Medio", question: "¿Qué es Session Replay en Datadog RUM?", options: ["Un backup de sesiones de usuario", "La grabación y reproducción de sesiones de usuario reales (movimientos de ratón, clics, scroll) para reproducir problemas de UX", "Un tipo de Synthetic test", "Un log de sesiones de servidor"], correctAnswer: 1, explanation: "Session Replay graba la interacción completa del usuario (movimientos, clics, scroll, formularios) de forma anonimizada y la reproduce como vídeo, permitiendo ver exactamente qué experimentó el usuario cuando ocurrió un error." },
          { id: 92, certification: "fundamentals", category: "Incident Management", difficulty: "Medio", question: "¿Qué es Incident Management en Datadog?", options: ["Un tipo de monitor crítico", "Una funcionalidad para declarar, coordinar y resolver incidentes de forma estructurada dentro de Datadog", "Un tipo de dashboard de incidentes", "Un servicio de soporte de Datadog"], correctAnswer: 1, explanation: "Incident Management permite declarar incidentes, asignar roles (incident commander, responders), actualizar el estado, vincular métricas/logs/trazas relacionados y generar post-mortems, todo sin salir de Datadog." },
          { id: 93, certification: "fundamentals", category: "Costes y licencias", difficulty: "Fácil", question: "¿Cómo se factura principalmente la monitorización de infraestructura en Datadog?", options: ["Por número de métricas almacenadas", "Por número de hosts monitorizados al mes", "Por volumen de datos enviados al Agent", "Por número de dashboards creados"], correctAnswer: 1, explanation: "La infraestructura de Datadog se factura principalmente por host-hora (número de hosts que reportan métricas al mes). Cada host con el Agent instalado cuenta como una unidad facturable." },
          { id: 94, certification: "fundamentals", category: "Costes y licencias", difficulty: "Medio", question: "¿Cómo se facturan los logs en Datadog?", options: ["Por número de líneas de log", "Por volumen ingerido (GB) y por volumen indexado (millones de eventos), con precios distintos", "Por número de pipelines de logs", "Por número de usuarios que consultan logs"], correctAnswer: 1, explanation: "Los logs tienen dos costes: ingesta (procesamiento y routing, precio por GB) e indexación (almacenamiento searchable, precio por millón de eventos indexados). Los logs enviados a archives sin indexar solo pagan la ingesta." },
          { id: 95, certification: "fundamentals", category: "Costes y licencias", difficulty: "Medio", question: "¿Qué son las custom metrics y cómo afectan a la facturación?", options: ["No afectan a la facturación", "Cada combinación única de nombre de métrica + conjunto de tags cuenta como una custom metric, facturada por unidad/mes", "Solo se facturan si superan 1000 por host", "Se facturan igual que las métricas de integraciones"], correctAnswer: 1, explanation: "Una custom metric es cada combinación única de nombre + tags. Ejemplo: 'requests.count{service:web, env:prod}' y 'requests.count{service:api, env:prod}' cuentan como 2 custom metrics. Se facturan por la cantidad media mensual." },
          { id: 96, certification: "fundamentals", category: "Plataforma Datadog", difficulty: "Medio", question: "¿Qué es el Datadog Events Explorer?", options: ["Un buscador de dashboards", "Una vista centralizada de eventos del sistema: deploys, alertas de monitors, cambios de configuración, eventos de cloud", "Un tipo de log especial", "Un tipo de monitor"], correctAnswer: 1, explanation: "El Events Explorer agrega eventos de toda la infraestructura: cambios de estado de monitors, deploys de código, escalados de Kubernetes, eventos de AWS, etc. Permite correlacionar incidentes con cambios del sistema." },
          { id: 97, certification: "fundamentals", category: "Plataforma Datadog", difficulty: "Medio", question: "¿Qué es el tag 'env' y por qué es especialmente importante en Datadog?", options: ["Es un tag automático del Agent", "Es uno de los tres tags del Unified Service Tagging que identifica el entorno (prod, staging, dev) y permite separar datos entre entornos", "Es obligatorio para usar APM", "Es un tag de facturación"], correctAnswer: 1, explanation: "El tag 'env' es parte del Unified Service Tagging (junto con 'service' y 'version'). Permite filtrar dashboards, monitores y logs por entorno. Sin él, los datos de producción y staging se mezclarían, dificultando el diagnóstico." },
          { id: 98, certification: "fundamentals", category: "Plataforma Datadog", difficulty: "Avanzado", question: "¿Qué es Datadog Software Catalog (anteriormente Service Catalog)?", options: ["Un catálogo de integraciones disponibles", "Un inventario centralizado de todos los servicios de la organización con información de ownership, SLOs, métricas y documentación", "Un tipo de dashboard de servicios", "Un tipo de integración"], correctAnswer: 1, explanation: "El Software Catalog centraliza información de todos los servicios: equipo responsable, on-call, runbooks, SLOs, métricas de salud y dependencias. Facilita la gobernanza y el onboarding cuando la organización tiene muchos servicios y equipos." },
          { id: 99, certification: "fundamentals", category: "Plataforma Datadog", difficulty: "Medio", question: "¿Qué son los Saved Views en el Log Explorer de Datadog?", options: ["Tipos de dashboards de logs", "Búsquedas guardadas con sus filtros, columnas y configuración de visualización para reutilizarlas en el futuro", "Un tipo de índice de logs", "Backups de configuración de logs"], correctAnswer: 1, explanation: "Las Saved Views guardan el estado completo del Log Explorer (query de búsqueda, filtros de tags, columnas visibles, visualización) con un nombre, permitiendo volver rápidamente a investigaciones frecuentes o compartirlas con el equipo." },
          { id: 100, certification: "fundamentals", category: "Plataforma Datadog", difficulty: "Medio", question: "¿Qué es la función 'correlate' entre métricas, logs y trazas en Datadog?", options: ["Una función matemática de correlación estadística", "La capacidad de navegar directamente desde una métrica o log a las trazas APM relacionadas del mismo servicio y momento", "Un tipo de dashboard correlacionado", "Una integración de análisis de datos"], correctAnswer: 1, explanation: "La correlación entre los tres pilares permite navegar desde una métrica anómala → logs del mismo host en ese momento → trazas APM del mismo servicio. Esto acelera drásticamente el diagnóstico de causa raíz (RCA) sin cambiar de herramienta." }
        ],
        concepts: [
          { title: "Datadog Agent", description: "Software ligero que se instala en hosts para recopilar métricas del sistema, ejecutar checks de integraciones y recopilar logs y trazas APM.", keyPoints: ["Configuración principal: /etc/datadog-agent/datadog.yaml", "Checks de integraciones en /etc/datadog-agent/conf.d/", "Comando de estado: datadog-agent status", "DogStatsD: recibe métricas custom vía UDP puerto 8125", "APM: recibe trazas en puerto TCP 8126", "Autodiscovery para contenedores y Kubernetes"] },
          { title: "Métricas y tipos", description: "Los datos numéricos que representan el estado de sistemas y aplicaciones a lo largo del tiempo.", keyPoints: ["Gauge: valor puntual que sube y baja (CPU, memoria)", "Count: número de eventos en un intervalo", "Rate: count normalizado por segundo", "Histogram: distribución estadística (p50, p95, p99, avg, max, count)", "Distribution (DDSketch): percentiles globalmente precisos", "Custom metrics: facturadas por combinación nombre+tags"] },
          { title: "Tags y etiquetado unificado", description: "Pares clave:valor que añaden contexto a métricas, logs y trazas para filtrar, agrupar y correlacionar.", keyPoints: ["Formato: clave:valor (env:prod, service:web, version:1.2)", "Unified Service Tagging: env + service + version en todos los datos", "Tags de host: aplicados a todas las métricas del host", "Template variables en dashboards usan tags", "Los tags permiten el multi-alert en monitores", "Esenciales para correlacionar los tres pilares"] },
          { title: "Dashboards", description: "Visualizaciones configurables para monitorizar métricas, logs, trazas y más en tiempo real.", keyPoints: ["Timeseries: evolución temporal de métricas", "Query Value: KPI único numérico", "Toplist: top N elementos por valor de métrica", "Heatmap: distribución de valores en el tiempo", "Template variables: filtros dinámicos globales del dashboard", "Notebooks: documentos colaborativos para análisis e incidentes"] },
          { title: "Monitors y alertas", description: "Reglas que evalúan condiciones sobre datos y generan notificaciones cuando se cumplen.", keyPoints: ["Estados: OK, Warn, Alert, No Data", "Tipos: Metric, Service Check, Log, APM, Anomaly, Forecast, Composite", "Multi-alert: evalúa por grupo (host, service) independientemente", "Downtime: silenciado programado para mantenimientos", "Composite: combina estados con AND/OR para reducir false positives", "Watchdog: detección automática de anomalías con ML"] },
          { title: "Log Management", description: "Ingesta, procesamiento, indexación y análisis de logs de toda la infraestructura.", keyPoints: ["Habilitar logs: logs_enabled: true en datadog.yaml", "Pipelines: secuencias de procesadores (Grok, Remapper, URL Parser)", "Índices: definen retención y presupuesto por tipo de log", "Exclusion filters: excluyen logs de bajo valor para reducir costes", "Archives: exportación a S3/GCS/Azure para retención larga", "Log-based metrics: métricas a partir de logs con retención de 15 meses"] },
          { title: "APM y trazas distribuidas", description: "Rastreo de peticiones a través de servicios distribuidos para medir rendimiento y detectar errores.", keyPoints: ["Traza: recorrido completo de una petición por todos los servicios", "Span: operación individual dentro de una traza", "Flame graph: visualización jerárquica del tiempo por operación", "Service Map: grafo automático de dependencias entre servicios", "SLO: objetivo de nivel de servicio con error budget", "Error Tracking: agrupación de errores similares en issues"] },
          { title: "Synthetic Monitoring", description: "Pruebas proactivas que simulan usuarios para verificar disponibilidad y rendimiento.", keyPoints: ["API tests: HTTP, DNS, TCP, SSL, gRPC desde múltiples ubicaciones", "Browser tests: graban y reproducen flujos de usuario en navegador real", "Multistep API tests: encadenan peticiones para flujos transaccionales", "Private Locations: agentes en infraestructura propia para apps internas", "Resultados contribuyen a SLOs de disponibilidad", "Detectan problemas antes de que afecten a usuarios reales"] },
          { title: "Integraciones", description: "Conectores que recopilan datos de tecnologías externas automáticamente.", keyPoints: ["Más de 700 integraciones oficiales", "Basadas en Agent: checks periódicos en hosts locales (Nginx, MySQL, Redis)", "Basadas en API/crawler: consultan APIs externas (AWS, GCP, Azure)", "Autodiscovery: aplica checks automáticamente a contenedores detectados", "Custom Connectors: via DogStatsD, API REST o SDKs", "Marketplace: integraciones adicionales de partners"] },
          { title: "Kubernetes y contenedores", description: "Monitorización de infraestructura contenerizada con el Datadog Agent.", keyPoints: ["Node Agent: DaemonSet con un pod por nodo", "Cluster Agent: métricas del plano de control y proxy de metadatos", "Autodiscovery: checks automáticos basados en annotations de pods", "Admission Controller: inyecta variables APM automáticamente", "Live Container Monitoring: vista en tiempo real de todos los contenedores", "NPM: monitorización de tráfico de red entre pods y servicios"] },
          { title: "Seguridad y administración", description: "Controles de acceso, auditoría y protección de datos en Datadog.", keyPoints: ["API Keys: autentican el envío de datos (Agent e integraciones)", "Application Keys: autentican llamadas a la API REST de Datadog", "RBAC: roles Admin, Standard, Read-Only y roles personalizados", "Audit Trail: registro inmutable de acciones en la plataforma", "Sensitive Data Scanner: enmascara PII y datos sensibles en logs", "Multi-org: organizaciones completamente aisladas para grandes empresas"] }
        ]
      }
};
